#include <stdio.h>
#include <stdint.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int G; int64_t P; int64_t X[11];
        scanf("%d %lld", &G, &P);
        for(int i=1;i<=10;i++) scanf("%lld", &X[i]);
        int64_t higher=0;
        for(int i=G+1;i<=10;i++) higher+=X[i];
        int64_t minDay = higher / P + 1;
        int64_t maxDay = (higher + X[G] + P - 1) / P;
        printf("%lld %lld\n", minDay, maxDay);
    }
    return 0;
}

