const fs = require('fs');
const input = fs.readFileSync(0, 'utf-8').trim().split(/\s+/).map(Number);
let idx = 0;
const T = input[idx++];
let out = [];
for (let t = 0; t < T; t++) {
  const G = input[idx++];
  const P = input[idx++];
  const X = [0];
  for (let i = 1; i <= 10; i++) X.push(input[idx++]);
  let higher = 0;
  for (let i = G + 1; i <= 10; i++) higher += X[i];
  const minDay = Math.floor(higher / P) + 1;
  const maxDay = Math.floor((higher + X[G] + P - 1) / P);
  out.push(minDay + ' ' + maxDay);
}
